import roundedTextBox from '../../css/roundedTextBox.module.css';


const InputWithImage = ({ icon, alt, type = 'text', placeholder, value, onChange, className }) => {
  return (
    <div className={`${roundedTextBox.input_block} ${className || ''}`}>
      <div>
        <img src={icon} alt={alt} style={{ width: '60%', height: '60%' }} />
      </div>
      <div>
        <input
          type={type}
          placeholder={placeholder}
          value={value}
          onChange={onChange}
        />
      </div>
    </div>
  );
};

export default InputWithImage;
